use quick_xml::Reader;
use quick_xml::events::Event;
use xml_rs::{XMLNode, XMLDocument};

fn parse_xml(data: &[u8]) -> Result<(), String> {
    let mut reader = Reader::from_reader(data);
    reader.trim_text(true);

    let mut buf = Vec::new();
    loop {
        match reader.read_event(&mut buf) {
            Ok(Event::StartElement { name, .. }) => {
                // Check if the element is a configuration setting
                if name == "configuration" {
                    // Extract the configuration settings from the XML file
                    let mut config = XMLNode::new();
                    config.parse(&mut reader)?;
                    println!("Configuration: {}", config);
                }
            },
            Ok(Event::EndDocument) => break, // End of XML document
            Err(e) => return Err(format!("Error parsing XML: {}", e)),
            _ => (), // Ignore other events
        };
    }

    Ok(())
}